// CONFIGURE HERE
var ALPACA_KEY_ID     = 'PASTE_YOUR_KEY_ID_HERE';
var ALPACA_SECRET_KEY = 'PASTE_YOUR_SECRET_KEY_HERE';
var MASSIVE_API_KEY   = 'PASTE_YOUR_MASSIVE_KEY_HERE';
var MAX_POSITIONS     = 3;

var alpacaHeaders = {
  'APCA-API-KEY-ID': ALPACA_KEY_ID,
  'APCA-API-SECRET-KEY': ALPACA_SECRET_KEY
};

var heldTickers = [];
try {
  var pos = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://paper-api.alpaca.markets/v2/positions',
    headers: alpacaHeaders
  });
  for (var pi = 0; pi < pos.length; pi++) {
    heldTickers.push(pos[pi].symbol);
  }
} catch(err) {}
if (heldTickers.length >= MAX_POSITIONS) return [];

var candidates = [];
try {
  var moversData = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://data.alpaca.markets/v1beta1/screener/stocks/movers?market_type=stocks&top=100',
    headers: alpacaHeaders
  });
  var movers = moversData.gainers || [];
  for (var mi = 0; mi < movers.length; mi++) {
    if (movers[mi].price >= 0.10 && movers[mi].price <= 15.0) {
      candidates.push(movers[mi].symbol);
    }
    if (candidates.length >= 20) break;
  }
} catch(e1) {
  try {
    var gainersData = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://api.polygon.io/v2/snapshot/locale/us/markets/stocks/gainers?apiKey=' + MASSIVE_API_KEY
    });
    var tickers = gainersData.tickers || [];
    for (var ti = 0; ti < tickers.length; ti++) {
      var tp = 0;
      if (tickers[ti].day && tickers[ti].day.c) {
        tp = tickers[ti].day.c;
      } else if (tickers[ti].lastTrade && tickers[ti].lastTrade.p) {
        tp = tickers[ti].lastTrade.p;
      }
      if (tp >= 0.10 && tp <= 15.0) {
        candidates.push(tickers[ti].ticker);
      }
      if (candidates.length >= 20) break;
    }
  } catch(e2) { return []; }
}

if (candidates.length === 0) return [];

function emaArr(vals, p) {
  var k = 2 / (p + 1);
  var r = [vals[0]];
  for (var i = 1; i < vals.length; i++) {
    r.push(vals[i] * k + r[i-1] * (1 - k));
  }
  return r;
}

function calcRSI(closes, p) {
  var ch = [];
  for (var i = 1; i < closes.length; i++) { ch.push(closes[i] - closes[i-1]); }
  var ag = 0; var al = 0;
  for (var i = 0; i < p; i++) {
    if (ch[i] > 0) { ag += ch[i]; } else { al += -ch[i]; }
  }
  ag /= p; al /= p;
  var out = [];
  for (var i = p; i < ch.length; i++) {
    ag = (ag * (p - 1) + Math.max(ch[i], 0)) / p;
    al = (al * (p - 1) + Math.max(-ch[i], 0)) / p;
    out.push(al === 0 ? 100 : 100 - 100 / (1 + ag / al));
  }
  return out;
}

function calcStochRSI(closes) {
  var rp = 14; var sp = 14; var ks = 3; var ds = 3;
  var rsi = calcRSI(closes, rp);
  if (rsi.length < sp + ks + ds) return null;
  var rawK = [];
  for (var i = sp - 1; i < rsi.length; i++) {
    var sl = rsi.slice(i - sp + 1, i + 1);
    var lo = sl[0]; var hi = sl[0];
    for (var j = 1; j < sl.length; j++) {
      if (sl[j] < lo) lo = sl[j];
      if (sl[j] > hi) hi = sl[j];
    }
    rawK.push(hi === lo ? 0 : (rsi[i] - lo) / (hi - lo) * 100);
  }
  var sK = [];
  for (var i = ks - 1; i < rawK.length; i++) {
    var sum = 0;
    for (var j = i - ks + 1; j <= i; j++) sum += rawK[j];
    sK.push(sum / ks);
  }
  var sD = [];
  for (var i = ds - 1; i < sK.length; i++) {
    var sum = 0;
    for (var j = i - ds + 1; j <= i; j++) sum += sK[j];
    sD.push(sum / ds);
  }
  if (sK.length < 2 || sD.length < 1) return null;
  return { k: sK[sK.length-1], kPrev: sK[sK.length-2], d: sD[sD.length-1] };
}

function calcZLSMA(closes, p) {
  if (closes.length < p * 2) return null;
  var e1 = emaArr(closes, p);
  var e2 = emaArr(e1, p);
  return 2 * e1[e1.length-1] - e2[e2.length-1];
}

var signals = [];

for (var ci = 0; ci < candidates.length; ci++) {
  var ticker = candidates[ci];
  if (heldTickers.indexOf(ticker) >= 0) continue;
  if (heldTickers.length + signals.length >= MAX_POSITIONS) break;

  try {
    var barsData = await $helpers.httpRequest({
      method: 'GET',
      url: 'https://data.alpaca.markets/v2/stocks/' + ticker + '/bars?timeframe=5Min&limit=100&feed=iex&adjustment=raw',
      headers: alpacaHeaders
    });
    var bars = barsData.bars;
    if (!bars || bars.length < 60) continue;

    var closes = [];
    for (var i = 0; i < bars.length; i++) { closes.push(bars[i].c); }
    var price = closes[closes.length - 1];
    if (price < 0.10 || price > 15.0) continue;

    var srsi = calcStochRSI(closes);
    if (!srsi) continue;

    // K must be trending up (K > D) — no upper limit, runs all day
    if (srsi.k <= srsi.d) continue;

    // Price above ZLSMA-50 — non-negotiable
    var zlsma = calcZLSMA(closes, 50);
    if (!zlsma || price <= zlsma) continue;

    // Volume >= 4x 20-bar average (matches TradingView Yassss: Rel Vol > 4)
    var vols = [];
    for (var i = bars.length - 21; i < bars.length - 1; i++) { vols.push(bars[i].v); }
    var avgVol = 0;
    for (var i = 0; i < vols.length; i++) { avgVol += vols[i]; }
    avgVol /= vols.length;
    var curVol = bars[bars.length - 1].v;
    if (curVol < avgVol * 4.0) continue;

    signals.push({
      json: {
        ticker: ticker,
        price: price,
        stop: parseFloat((price * 0.92).toFixed(2)),
        t1: parseFloat((price * 1.15).toFixed(2)),
        t2: parseFloat((price * 1.30).toFixed(2)),
        t3: parseFloat((price * 1.60).toFixed(2)),
        qty: 10,
        qty_t1: 3,
        qty_t2: 3,
        qty_t3: 4,
        k: srsi.k.toFixed(1),
        d: srsi.d.toFixed(1),
        vol_ratio: (curVol / avgVol).toFixed(1),
        deep_reset: srsi.kPrev < 15,
        ALPACA_KEY_ID: ALPACA_KEY_ID,
        ALPACA_SECRET_KEY: ALPACA_SECRET_KEY
      }
    });
  } catch(e) {}
}

return signals;

